In JavaScript:
1. Add event listeners to all number buttons
2. Implement logic to update the current input value when number buttons are clicked
3. Handle cases where a new number should replace the display (after operation selection) vs. append to existing input

```javascript
// Example number input handling
let currentInput = '0';
let newInput = false; // Flag to determine if input should be replaced or appended

function handleNumberInput(num) {
  if (currentInput === '0' || newInput) {
    currentInput = num;
    newInput = false;
  } else {
    currentInput += num;
  }
  updateDisplay(currentInput);
}

// Add event listeners to number buttons
document.querySelectorAll('.number-btn').forEach(button => {
  button.addEventListener('click', () => {
    handleNumberInput(button.textContent);
  });
});
```

In JavaScript:
1. Add event listener to the decimal point button
2. Implement logic to add a decimal point to the current input
3. Ensure only one decimal point can be added to a number

```javascript
function handleDecimalPoint() {
  if (!currentInput.includes('.')) {
    currentInput += '.';
  }
  updateDisplay(currentInput);
}

// Add event listener to decimal button
document.querySelector('.decimal-btn').addEventListener('click', handleDecimalPoint);
```

Update the number input handling to work with decimal values.

In JavaScript:
1. Create variables to store the first operand and the selected operation
2. Add event listeners to operation buttons
3. Implement logic to handle operation selection

```javascript
let firstOperand = null;
let operation = null;

function handleOperation(op) {
  firstOperand = parseFloat(currentInput);
  operation = op;
  newInput = true; // Set flag to replace input on next number entry
}

// Add event listeners to operation buttons
document.querySelectorAll('.operation-btn').forEach(button => {
  button.addEventListener('click', () => {
    handleOperation(button.textContent);
  });
});
```

Implement a calculate function that performs the selected operation:

```javascript
function calculate() {
  if (firstOperand === null || operation === null) return;

  const secondOperand = parseFloat(currentInput);
  let result;

  switch(operation) {
    case '+':
      result = firstOperand + secondOperand;
      break;
    case '-':
      result = firstOperand - secondOperand;
      break;
    case '*':
      result = firstOperand * secondOperand;
      break;
    case '/':
      result = secondOperand !== 0 ? firstOperand / secondOperand : 'Error';
      break;
  }

  currentInput = result.toString();
  updateDisplay(currentInput);
  firstOperand = null;
  operation = null;
  newInput = true;
}
```

In JavaScript:
1. Add event listener to the clear button
2. Implement clear function to reset all calculator variables and display

```javascript
function clearCalculator() {
  currentInput = '0';
  firstOperand = null;
  operation = null;
  newInput = false;
  updateDisplay(currentInput);
}

// Add event listener to clear button
document.querySelector('.clear-btn').addEventListener('click', clearCalculator);
```

Consider implementing two types of clear:
- AC (All Clear): Resets everything
- C (Clear): Clears only the current input

In CSS:
